import json
import re

result_file_1 = locals()['var_functions.query_db:34']
result_file_2 = locals()['var_functions.query_db:30']
result_file_3 = locals()['var_functions.query_db:32']

with open(result_file_1, 'r') as f:
    packages = json.load(f)

with open(result_file_2, 'r') as f:
    package_versions = json.load(f)

with open(result_file_3, 'r') as f:
    project_info = json.load(f)

dict_packages = {(p['System'], p['Name'], p['Version']): p for p in packages}

key_to_project = {}
for pv in package_versions:
    key = (pv['System'], pv['Name'], pv['Version'])
    if key in dict_packages:
        key_to_project[key] = pv['ProjectName']

project_name_to_package_names = {}
for key, project_name in key_to_project.items():
    if project_name not in project_name_to_package_names:
        project_name_to_package_names[project_name] = []
    project_name_to_package_names[project_name].append(f"{key[1]}@{key[2]}")

fork_pattern = re.compile(r'(\d+) forks')
project_text_to_forks = {}
for info in project_info:
    text = info['Project_Information']
    match = fork_pattern.search(text)
    if match:
        forks = int(match.group(1))
        project_text_to_forks[text] = forks

project_results = []
for info in project_info:
    text = info['Project_Information']
    if text in project_text_to_forks:
        for project_name in project_name_to_package_names:
            if project_name in text.lower() or project_name.replace('/', '\/') in text:
                forks = project_text_to_forks[text]
                licenses = info.get('Licenses', '[]') if info.get('Licenses') else '[]'
                if 'MIT' in licenses:
                    project_results.append({
                        'package_names': project_name_to_package_names[project_name],
                        'project_name': project_name,
                        'forks': forks,
                        'project_info': text[:200] + '...',
                        'licenses': licenses
                    })

top_5 = sorted(project_results, key=lambda x: x['forks'], reverse=True)[:10]
print('__RESULT__:')
print(json.dumps({'count': len(top_5), 'top': top_5}))

